#!/usr/bin/env node

const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');
const { spawnSync } = require('node:child_process');

const root = path.resolve(__dirname, '..');
const outputDir = path.join(root, 'media', 'kicanvas');
const outputFile = path.join(outputDir, 'kicanvas.js');
const noticeFile = path.join(outputDir, 'NOTICE.txt');
const upstreamRef = process.env.KICANVAS_REF || 'latest';
const upstreamRepo = 'https://github.com/theacodes/kicanvas.git';

function isCommitSha(value) {
  return /^[0-9a-f]{7,40}$/i.test(value);
}
function run(command, args, cwd) {
  const result = spawnSync(command, args, {
    cwd,
    stdio: 'pipe',
    encoding: 'utf8'
  });
  if (result.status !== 0) {
    throw new Error(
      [result.stdout, result.stderr].filter(Boolean).join('\n').trim() ||
        `${command} ${args.join(' ')} failed`
    );
  }
  return result.stdout.trim();
}

function resolveRequestedRef(repoUrl) {
  if (upstreamRef !== 'latest') {
    return upstreamRef;
  }

  const tags = run(
    'git',
    ['ls-remote', '--tags', '--sort=-version:refname', repoUrl],
    root
  )
    .split(/\r?\n/)
    .map((line) => line.trim())
    .filter(Boolean)
    .map((line) => line.split(/\s+/)[1])
    .filter(Boolean)
    .filter((ref) => !ref.endsWith('^{}'));

  if (tags[0]) {
    return tags[0].replace('refs/tags/', '');
  }

  return 'main';
}

function writeFallbackBundle(target) {
  const fallback = `/**
 * Lightweight KiCanvas-compatible fallback bundle generated by KiCad Studio.
 * This file is used only when the upstream KiCanvas bundle cannot be fetched.
 */
class KicanvasEmbed extends HTMLElement {
  static get observedAttributes() { return ['src']; }
  constructor() {
    super();
    this.attachShadow({ mode: 'open' });
    this.shadowRoot.innerHTML = \`
      <style>
        :host {
          display: block;
          width: 100%;
          height: 100%;
          background: linear-gradient(180deg, #0f172a, #111827);
          color: #e2e8f0;
          border: 1px solid rgba(148, 163, 184, 0.2);
          border-radius: 12px;
          overflow: hidden;
        }
        .frame {
          display: grid;
          grid-template-rows: auto 1fr;
          width: 100%;
          height: 100%;
        }
        .header {
          padding: 12px 16px;
          font: 600 13px/1.4 sans-serif;
          border-bottom: 1px solid rgba(148, 163, 184, 0.2);
          background: rgba(15, 23, 42, 0.6);
        }
        pre {
          margin: 0;
          padding: 16px;
          overflow: auto;
          white-space: pre-wrap;
          word-break: break-word;
          font: 12px/1.5 ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
        }
      </style>
      <div class="frame">
        <div class="header">KiCanvas fallback viewer</div>
        <pre id="content">No source loaded.</pre>
      </div>
    \`;
  }
  attributeChangedCallback(name, _oldValue, newValue) {
    if (name === 'src') {
      this.loadSource(newValue);
    }
  }
  async loadSource(src) {
    const content = this.shadowRoot.getElementById('content');
    if (!src) {
      content.textContent = 'No source loaded.';
      return;
    }
    try {
      const response = await fetch(src);
      const text = await response.text();
      content.textContent = text;
      this.dispatchEvent(new CustomEvent('kicad-ready', { detail: { length: text.length } }));
    } catch (error) {
      content.textContent = 'Unable to load KiCad content. ' + error;
    }
  }
  zoomIn() {}
  zoomOut() {}
  fitToScreen() {}
  toggleGrid() {}
}
customElements.define('kicanvas-embed', KicanvasEmbed);
`;
  fs.writeFileSync(target, fallback, 'utf8');
}

fs.mkdirSync(outputDir, { recursive: true });

if (fs.existsSync(outputFile)) {
  const stat = fs.statSync(outputFile);
  if (stat.size < 50 * 1024) {
    fs.unlinkSync(outputFile);
  }
}

if (!fs.existsSync(outputFile)) {
  const tempRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'kicanvas-'));
  const repoDir = path.join(tempRoot, 'repo');
  try {
    const requestedRef = resolveRequestedRef(upstreamRepo);
    fs.mkdirSync(repoDir, { recursive: true });
    run('git', ['init'], repoDir);
    run('git', ['remote', 'add', 'origin', upstreamRepo], repoDir);
    if (isCommitSha(requestedRef)) {
      run('git', ['fetch', '--depth', '1', 'origin', requestedRef], repoDir);
      run('git', ['checkout', '--detach', 'FETCH_HEAD'], repoDir);
    } else {
      run('git', ['fetch', '--depth', '1', 'origin', requestedRef], repoDir);
      run('git', ['checkout', 'FETCH_HEAD'], repoDir);
    }
    if (process.platform === 'win32') {
      run('cmd', ['/c', 'npm', 'ci'], repoDir);
      run('cmd', ['/c', 'npm', 'run', 'build'], repoDir);
    } else {
      run('npm', ['ci'], repoDir);
      run('npm', ['run', 'build'], repoDir);
    }

    const builtFile = path.join(repoDir, 'build', 'kicanvas.js');
    if (!fs.existsSync(builtFile)) {
      throw new Error(
        'KiCanvas build completed without producing build/kicanvas.js'
      );
    }
    const resolvedRef = run('git', ['rev-parse', 'HEAD'], repoDir);
    fs.copyFileSync(builtFile, outputFile);
    fs.writeFileSync(
      noticeFile,
      `KiCanvas bundle sourced from https://github.com/theacodes/kicanvas at ${resolvedRef} (requested ref: ${requestedRef}) under the MIT license.\n`,
      'utf8'
    );
  } catch (error) {
    writeFallbackBundle(outputFile);
    fs.writeFileSync(
      noticeFile,
      `KiCanvas upstream bundle at ${upstreamRef} could not be fetched at build time. Using fallback viewer.\n${String(error)}\n`,
      'utf8'
    );
  } finally {
    fs.rmSync(tempRoot, { recursive: true, force: true });
  }
}
